// Attach chunk-level metadata before embedding
return $input.all().map((item, i) => ({
  json: {
    ...item.json,
    chunkIndex: i,
    sourceUrl: item.json.sourceUrl || item.json.url || 'internal',
    ingestedAt: new Date().toISOString(),
  },
}));

// Compare current metrics with the previous snapshot
const current = $input.first().json;
const prev = $('Load Previous Snapshot').first().json || {};
const drift = {};
for (const k of Object.keys(current)) {
  if (typeof current[k] === 'number' && typeof prev[k] === 'number' && prev[k] !== 0) {
    drift[k] = Math.round(((current[k] - prev[k]) / prev[k]) * 1000) / 10;
  }
}
return [{ json: { ...current, driftPct: drift, hasDrift: Object.values(drift).some(v => Math.abs(v) > 10) } }];
